### 개선 3: JPQL fetch join으로 N+1 제거

```kotlin
// repository/user/UserRepositoryCustom.kt (QueryDSL 커스텀 구현)
interface UserRepositoryCustom {
    fun findByNicknameWithProfile(nickname: String): UserWithProfileDto?
}

// repository/user/UserRepositoryImpl.kt
@Repository
class UserRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : UserRepositoryCustom {

    override fun findByNicknameWithProfile(nickname: String): UserWithProfileDto? {
        val user = QUserEntity.userEntity
        val profile = QProfileEntity.profileEntity

        return queryFactory
            .select(
                // Projection으로 필요한 데이터만 SELECT
                Projections.constructor(
                    UserWithProfileDto::class.java,
                    user.id,
                    user.nickname,
                    user.status,
                    profile.imageUrl,
                    profile.bio
                )
            )
            .from(user)
            // fetch join으로 N+1 제거: 단일 쿼리로 user + profile 조회
            .leftJoin(profile).on(profile.userId.eq(user.id))
            .where(
                user.nickname.eq(nickname),
                user.status.eq(1)   // 활성 유저 필터
            )
            .fetchOne()
    }
}

data class UserWithProfileDto(
    val id: String,
    val nickname: String,
    val status: Int,
    val imageUrl: String?,
    val bio: String?
)
```

### 개선 4: Redis 캐시 전략 적용

```kotlin
// service/UserService.kt  (개선 후)
@Service
class UserService(
    private val userRepository: UserRepository,
    private val redisTemplate: RedisTemplate<String, UserWithProfileDto>
) {
    companion object {
        private const val CACHE_KEY_PREFIX = "user:nickname:"
        private val CACHE_TTL = Duration.ofMinutes(10)  // TTL: 10분
    }

    fun getUserByNickname(nickname: String): UserWithProfileDto? {
        val cacheKey = "$CACHE_KEY_PREFIX$nickname"

        // 1. Redis 캐시에서 먼저 조회
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) {
            return cached  // 캐시 히트: DB 쿼리 없음
        }

        // 2. 캐시 미스 시 DB 조회 (인덱스 + fetch join 최적화된 쿼리)
        val user = userRepository.findByNicknameWithProfile(nickname)
            ?: return null

        // 3. 결과를 Redis에 캐시 저장
        redisTemplate.opsForValue().set(cacheKey, user, CACHE_TTL)

        return user
    }

    // 닉네임 변경 시 캐시 무효화
    fun updateNickname(userId: String, oldNickname: String, newNickname: String) {
        // 비즈니스 로직 처리...

        // 캐시 무효화: 구 닉네임 캐시 삭제
        redisTemplate.delete("$CACHE_KEY_PREFIX$oldNickname")
    }
}
